"use strict";
import React from "react";
export async function getRoutes() {
  const routes = { "1": { "path": "/", "id": "1" }, "2": { "path": "/pricing", "id": "2" }, "3": { "path": "/register", "id": "3" } };
  return {
    routes,
    routeComponents: {
      "1": React.lazy(() => import(
        /* webpackChunkName: "p__index" */
        "@/pages/index.tsx"
      )),
      "2": React.lazy(() => import(
        /* webpackChunkName: "p__pricing" */
        "@/pages/pricing.tsx"
      )),
      "3": React.lazy(() => import(
        /* webpackChunkName: "p__register" */
        "@/pages/register.tsx"
      ))
    }
  };
}
